// Lee el payload del backend (Spring Boot -> n8n). El cuerpo del POST llega bajo .body.
const data = $input.first().json.body || $input.first().json || {};
const est = data.estudiante || {};
const nReceta = String(data.idReceta || '').padStart(4, '0');

// El cuerpo del correo es un mensaje único; el detalle completo va en el PDF adjunto.
const html = 'Se adjunta la prescripción médica y los procedimientos médicos';

const out = {
  json: {
    to: est.email,
    subject: `Receta médica N° ${nReceta} - Centro Médico UNI`,
    html
  }
};

// Adjunto PDF: el backend lo manda en base64 (data.pdfBase64).
if (data.pdfBase64) {
  out.binary = {
    receta: {
      data: data.pdfBase64,
      fileName: data.pdfNombre || `receta-${nReceta}.pdf`,
      mimeType: 'application/pdf'
    }
  };
}

return [out];
